import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"黑骑士套装","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/黑骑士套装.md","filePath":"4.资源分区/7.物品与装备/6.套装/黑骑士套装.md"}'),s={name:"4.资源分区/7.物品与装备/6.套装/黑骑士套装.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"黑骑士套装",tabindex:"-1"},[p("黑骑士套装 "),r("a",{class:"header-anchor",href:"#黑骑士套装","aria-label":'Permalink to "黑骑士套装"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),n('<h1 id="黑骑士套装-1" tabindex="-1">黑骑士套装 <a class="header-anchor" href="#黑骑士套装-1" aria-label="Permalink to &quot;黑骑士套装&quot;">​</a></h1><p>黑骑士套装<br> 介绍：<br> 本资源所陈列的，是《黑暗之魂》系列中黑骑士的装备。黑骑士是追随阳光之王“葛温”的银骑士当中的精锐，在葛温成为柴薪，再次点燃初火之后，他们亦成为了灰，在世界之中徘徊。</p><p>黑骑士头盔<br> 价格：C+1000<br> 描述：被火焰灼烧过而显露出黑色的古朴头盔，有竖起的一对尖角。<br> 本物品占据头盔位。具有9/9的盔甲防御。<br> 【黑骑士】：黑骑士的意志即使灼烧成灰，也未曾动摇。你每具有一点决心上的附加成功，你就获得1点基于盔甲防御的DR/-。</p><p>黑骑士铠甲<br> 价格：C+2000<br> 描述：被火焰灼烧过而显露出黑色的古朴铠甲，其上狰狞的烧灼痕迹不禁令人生畏。<br> 本物品为重甲。具有12/12的盔甲防御和两点盔甲减值，具有8点抵破甲。<br> 【黑骑士】：黑骑士是追随王的精锐，难以被敌人撼动。你每具有一点耐力上的附加成功，你就获得1点盔甲防御上的附加成功。</p><p>黑骑士臂甲<br> 价格：C+1000<br> 描述：被火焰灼烧过而显露出黑色的古朴臂甲，其上具有层叠的甲片。<br> 本物品占据手臂位。具有4/4的盔甲防御。<br> 【黑骑士】：黑骑士是能够讨伐古龙与恶魔的强者，可以使得神话般的存在在自己的攻击前动摇。你每具有一点力量上的附加成功，你就在进行白刃攻击时获得5点威猛。</p><p>黑骑士腿甲<br> 价格：C+1500<br> 描述：被火焰灼烧过而显露出黑色的古朴臂甲，铸造时运用的华美工艺已经模糊。<br> 本物品占据下肢-躯干位。具有6/6的盔甲防御。<br> 【黑骑士】：黑骑士是徘徊于世的灰烬，身形飘忽不定。以一个标准动作启动，持续一个场景，你变为虚体，你可以随时以一个自由动作解除自身的虚体状态。</p><p>黑骑士剑<br> 价格：C+1000<br> 描述：于罗德兰四处徘徊的黑骑士的长剑，古朴而沉重，对于一般体型的生物来说，可以当成是大剑来使用。是对抗混沌恶魔用的武器。<br> 大动作再加上自身体重使出的攻击，是因应当时的强敌而出现的战法。<br> 黑骑士剑是一柄具有10L武器伤害和5破甲的重剑。<br> 【对恶魔战法】：黑骑士用于击溃身形庞大，体格健壮，生命力顽强的混沌恶魔所使用的战技，连续向前踏步斩出斩击，将敌人击退。<br> 以一个标准动作，消耗2点意志使用，你对于你对于你触及范围内一个的敌人进行三次攻击。<br> 第一次攻击不造成实际伤害，也不会能触发任何挂靠在攻击上的效果，而是在你命中之后，你每具有1点武技上的附加成功，被攻击的对象会在这个技艺施展结束之前，在基础防御和闪避防御上受到2点减值，自由分配。<br> 第二次攻击不造成实际伤害，也不会能触发任何挂靠在攻击上的效果，而是在你命中之后，你每具有1点力量上的附加成功，你的下一次攻击上获得3点技艺加值。<br> 第三次攻击是一次如常造成伤害的白刃攻击。</p><p>黑骑士盾<br> 价格：C+1500<br> 描述：于罗德兰四处徘徊的黑骑士的大盾，古朴而沉重，盾面刻有深刻的沟槽。前端尖锐，也可以当做突刺武器使用。<br> 黑骑士过去曾对抗混沌恶魔，他们的盾因此熏黑，对火焰有高防御效果。<br> 黑骑士剑是一面具有7L武器伤害，造成突刺伤害。具有【双手】和【格挡11】<br> 【抵挡火焰】：这面盾牌额外具有10点火焰抗力。</p><p>黑骑士大剑<br> 价格：C+3000<br> 描述：于罗德兰四处徘徊的黑骑士的巨剑，古朴而沉重，虽然身为神族的黑骑士可以单手挥舞，但是对于身为人类的不死人来说，这把武器无疑巨大得过于夸张。<br> 大动作再加上自身体重使出的攻击，是因应当时的强敌而出现的战法。<br> 黑骑士剑是一柄具有18L武器伤害，具有【双手】和【沉重武器】特性的重剑，并且体积提升到8，但也因为过于庞大，难以运用，获得1点攻击上的器械减值。<br> 【对恶魔战法】：黑骑士用于击溃身形庞大，体格健壮，生命力顽强的混沌恶魔所使用的战技，回转身躯，将全身的力量汇聚于巨剑之上，然后一举刺出。<br> 以一个整轮动作，消耗2点意志使用，你对于你对于你触及范围内的一个敌人进行一次攻击，这次攻击造成突刺伤害，并且额外具有5点破甲和【贯穿】特性。<br> 你每具有一点武技上的附加成功，就可以将你这次攻击上的一点附加成功转化为5点攻击上的技艺加值，并且这次攻击具有8加骰，若已具有8加骰，则额外获得攻击上的9点技艺加值。<br> 一轮一次，你进行完这次攻击后，可以以一个自由动作对受到该次攻击的对象进行一次冲撞。</p><p>黑骑士斧<br> 价格：C+3000<br> 描述：于罗德兰四处徘徊的黑骑士的大斧，古朴而沉重，虽然身为神族的黑骑士可以单手挥舞，但是对于身为人类的不死人来说，这把武器无疑巨大得难以掌控。<br> 大动作再加上自身体重使出的攻击，是因应当时的强敌而出现的战法。<br> 黑骑士斧是一柄具有15L武器伤害，具有【双手】和【沉重武器】特性的斧，并且体积提升到8，但也因为过于庞大，难以运用，获得1点攻击上的器械减值。在发动斧基础模板的全力攻击的效果时，你可以再额外承受3点基础防御上的器械减值，让你在攻击上获得3点附加成功。<br> 【对恶魔战法】：黑骑士用于击溃身形庞大，体格健壮，生命力顽强的混沌恶魔所使用的战技，将巨大的斧刃在地面上拖行，然后猛然扬起，将对手击飞。<br> 以一个整轮动作，消耗2点意志使用，你对于你对于你触及范围内的一个敌人进行一次攻击。在这次攻击中，黑骑士在使用斧基础模板的全力攻击效果时，还可以再额外获得1点附加成功。<br> 并且这次攻击在命中后会附带等同成功数的冲击点数（强韧豁免）和C级别的【击飞】效果。当这次攻击命中时，你每具有1点力量上的附加成功，对方在这次技艺的相关效果结算完成前在强韧豁免上就具有3点器械减值，这次攻击带来的效果与器械减值均为C级别创伤来源。</p><p>黑骑士戟<br> 价格：C+3000<br> 描述：于罗德兰四处徘徊的黑骑士的长戟，古朴而沉重，拥有着迥异的形制，给人一种异国的印象，不过的确是性能优异的武器。<br> 大动作再加上自身体重使出的攻击，是因应当时的强敌而出现的战法。<br> 黑骑士斧是一柄具有15L武器伤害和5点破甲，具有【双手】和【长柄】以及【格挡2】特性的戟。<br> 【对恶魔战法】：黑骑士用于击溃身形庞大，体格健壮，生命力顽强的混沌恶魔所使用的战技，将长柄的黑骑士戟举起，然后连续旋转，荡开逼近的敌人<br> 以一个整轮动作，消耗2点意志使用，你如常进行一次移动，并在这次攻击中结合一次攻击，这次攻击对你触及范围内的所有人进行,并且改为以反射判定进行豁免。<br> 只要你施展了这个招式，这一轮内，你额外获得4点格挡防御。</p><p>【套装效果】<br> 穿戴4件黑骑士防具，会令你获得基于盔甲防御的【封闭1】<br> 因为黑骑士是体格高大的神族，所以当你穿戴了全部的4件黑骑士防具时，你每具有1点耐力上的附加成功，你的体积就增大1点。<br> 黑骑士套装会赋予穿戴者极其强大的韧性，所以当你穿戴了全部的4件黑骑士防具时，你具有【超级坚韧】特性。</p><p>当你同时装备了黑骑士盾与任意一柄黑骑士武器时，只要你在一轮中进行过以黑骑士盾进行的格挡，那么你在这一轮中的白刃攻击获得2点附加成功，只要你在一轮中进行过以黑骑士武器进行的白刃攻击，那么你在防御上获得2点基于格挡防御的附加成功。这两项好处可以被同时取得。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const f=e(s,[["render",o]]);export{C as __pageData,f as default};
